fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val valid = mutableListOf<Pair<String, String>>()
    val businessOrder = mapOf("electronics" to 0, "grocery" to 1, "pharmacy" to 2, "restaurant" to 3)

    for (i in code.indices) {
        val c = code[i]
        val bl = businessLine[i]
        val active = isActive[i]

        if (c.isEmpty()) continue
        if (!c.matches(Regex("[a-zA-Z0-9_]+"))) continue
        if (bl !in businessOrder.keys) continue
        if (!active) continue

        valid.add(Pair(c, bl))
    }

    valid.sortWith(compareBy<Pair<String, String>> { pair ->
        businessOrder[pair.second]!!
    }.thenCompareBy { it.first })

    return valid.map { it.first }.toTypedArray()
}
